package main

import (
	"bytes"
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
)

// TestPlanGoldenFixtures pins the JSON output of `fiz-bench plan --json` for
// representative profile × bench-set invocations. The fixtures live under
// cmd/bench/testdata/plans/ and are committed alongside the helper so the
// shell driver (scripts/benchmark/benchmark) and analytics tooling stay in
// lockstep with the manifest schema (ADR-016, plan PR 1d).
//
// Regenerate after intentional schema changes with:
//
//	go test ./cmd/bench -run TestPlanGoldenFixtures -update
//
// (The -update flag is implemented inline below; ad-hoc invocations of
// fiz-bench plan --json also work but byte-for-byte parity matters.)
func TestPlanGoldenFixtures(t *testing.T) {
	wd, err := os.Getwd()
	if err != nil {
		t.Fatal(err)
	}
	repoRoot := filepath.Join(wd, "..", "..")
	profilesDir := filepath.Join(repoRoot, "scripts", "benchmark", "profiles")
	benchSetsDir := filepath.Join(repoRoot, "scripts", "benchmark", "bench-sets")
	concurrencyPath := filepath.Join(repoRoot, "scripts", "benchmark", "concurrency-groups.yaml")
	fixturesDir := filepath.Join(wd, "testdata", "plans")

	cases := []struct {
		name        string
		profileList string
		benchSetID  string
		fixture     string
	}{
		{
			name:        "vidar-ds4 × tb-2-1-timing-baseline",
			profileList: "vidar-ds4",
			benchSetID:  "tb-2-1-timing-baseline",
			fixture:     "vidar-ds4_tb-2-1-timing-baseline.json",
		},
		{
			name:        "sindri-llamacpp,vidar-ds4 × tb-2-1-or-passing",
			profileList: "sindri-llamacpp,vidar-ds4",
			benchSetID:  "tb-2-1-or-passing",
			fixture:     "sindri-llamacpp_vidar-ds4_tb-2-1-or-passing.json",
		},
	}

	groups, err := loadConcurrencyGroups(concurrencyPath)
	if err != nil {
		t.Fatalf("loadConcurrencyGroups: %v", err)
	}

	for _, c := range cases {
		t.Run(c.name, func(t *testing.T) {
			bs, err := loadBenchSet(filepath.Join(benchSetsDir, c.benchSetID+".yaml"))
			if err != nil {
				t.Fatalf("loadBenchSet: %v", err)
			}
			profiles, err := resolveProfiles(profilesDir, splitCSV(c.profileList))
			if err != nil {
				t.Fatalf("resolveProfiles: %v", err)
			}
			plan, err := buildPlan(profiles, bs, 0, groups)
			if err != nil {
				t.Fatalf("buildPlan: %v", err)
			}
			got, err := json.MarshalIndent(plan, "", "  ")
			if err != nil {
				t.Fatalf("marshal: %v", err)
			}
			// Match the trailing newline emitted by the CLI's `fmt.Println`.
			got = append(got, '\n')

			fixturePath := filepath.Join(fixturesDir, c.fixture)
			want, err := os.ReadFile(fixturePath)
			if err != nil {
				t.Fatalf("read fixture: %v", err)
			}
			if !bytes.Equal(got, want) {
				if shouldUpdateGolden() {
					if err := os.WriteFile(fixturePath, got, 0o644); err != nil {
						t.Fatalf("rewrite fixture: %v", err)
					}
					t.Logf("updated %s", fixturePath)
					return
				}
				t.Fatalf("plan output drift; rerun with -update or compare with:\n  diff %s <(go run ./cmd/bench plan --profile %s --bench-set %s --json --profiles-dir %s --bench-sets-dir %s --concurrency-groups %s)",
					fixturePath, c.profileList, c.benchSetID, profilesDir, benchSetsDir, concurrencyPath)
			}

			// Sanity: cell count = profiles × tasks × default_reps.
			expected := len(profiles) * len(bs.Tasks) * bs.DefaultReps
			if len(plan.Cells) != expected {
				t.Fatalf("cells: got %d, want %d", len(plan.Cells), expected)
			}
		})
	}
}

func shouldUpdateGolden() bool {
	for _, arg := range os.Args {
		if arg == "-update" || arg == "--update" {
			return true
		}
	}
	return false
}

// plan.go: `fiz-bench plan --json` helper for the new ./benchmark shell
// driver (ADR-016, plan PR 1d). Loads one or more profile YAMLs plus a
// bench-set YAML, cross-references them against
// scripts/benchmark/concurrency-groups.yaml, and emits a JSON document the
// shell driver consumes to expand the execution matrix.
//
// The helper is pure: no file writes outside stdout, no endpoint probes, no
// benchmark-results/ directory creation. Schema additions require a spec
// amendment so the shell driver and golden fixtures stay in lockstep.
package main

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"

	"github.com/easel/fizeau/internal/benchmark/profile"
	"gopkg.in/yaml.v3"
)

const (
	defaultBenchSetsDir         = "scripts/benchmark/bench-sets"
	defaultConcurrencyGroupsRel = "scripts/benchmark/concurrency-groups.yaml"
)

// benchSet mirrors the YAML schema authored under scripts/benchmark/bench-sets/.
// Schema is frozen by ADR-016; additive fields require a spec amendment.
type benchSet struct {
	ID          string   `yaml:"id"            json:"id"`
	Framework   string   `yaml:"framework"     json:"framework"`
	Dataset     string   `yaml:"dataset"       json:"dataset"`
	DefaultReps int      `yaml:"default_reps"  json:"default_reps"`
	Description string   `yaml:"description"   json:"description,omitempty"`
	Tasks       []string `yaml:"-"             json:"tasks"`
	// AllTasks signals "tasks: all" — defer task enumeration to the harness
	// dataset rather than encoding it in the bench-set YAML.
	AllTasks bool `yaml:"-"             json:"all_tasks,omitempty"`
}

// rawBenchSet captures the YAML literal before normalizing the `tasks` field,
// which accepts either a list of task IDs or the bare string "all".
type rawBenchSet struct {
	ID          string    `yaml:"id"`
	Framework   string    `yaml:"framework"`
	Dataset     string    `yaml:"dataset"`
	DefaultReps int       `yaml:"default_reps"`
	Description string    `yaml:"description"`
	Tasks       yaml.Node `yaml:"tasks"`
}

func loadBenchSet(path string) (*benchSet, error) {
	raw, err := os.ReadFile(path) // #nosec G304 -- operator-supplied bench-set path
	if err != nil {
		return nil, fmt.Errorf("read bench-set %s: %w", path, err)
	}
	var r rawBenchSet
	dec := yaml.NewDecoder(strings.NewReader(string(raw)))
	dec.KnownFields(true)
	if err := dec.Decode(&r); err != nil {
		return nil, fmt.Errorf("parse bench-set %s: %w", path, err)
	}
	bs := &benchSet{
		ID:          r.ID,
		Framework:   r.Framework,
		Dataset:     r.Dataset,
		DefaultReps: r.DefaultReps,
		Description: strings.TrimSpace(r.Description),
	}
	switch r.Tasks.Kind {
	case yaml.ScalarNode:
		if strings.TrimSpace(r.Tasks.Value) != "all" {
			return nil, fmt.Errorf("bench-set %s: tasks scalar must be \"all\", got %q", path, r.Tasks.Value)
		}
		bs.AllTasks = true
	case yaml.SequenceNode:
		for _, child := range r.Tasks.Content {
			if child.Kind != yaml.ScalarNode {
				return nil, fmt.Errorf("bench-set %s: tasks entries must be scalars", path)
			}
			v := strings.TrimSpace(child.Value)
			if v == "" {
				continue
			}
			bs.Tasks = append(bs.Tasks, v)
		}
	case 0:
		return nil, fmt.Errorf("bench-set %s: tasks field is required", path)
	default:
		return nil, fmt.Errorf("bench-set %s: unsupported tasks node kind %v", path, r.Tasks.Kind)
	}
	if err := bs.validate(); err != nil {
		return nil, fmt.Errorf("validate bench-set %s: %w", path, err)
	}
	return bs, nil
}

func (b *benchSet) validate() error {
	if strings.TrimSpace(b.ID) == "" {
		return fmt.Errorf("id is required")
	}
	if strings.TrimSpace(b.Framework) == "" {
		return fmt.Errorf("framework is required")
	}
	if strings.TrimSpace(b.Dataset) == "" {
		return fmt.Errorf("dataset is required")
	}
	if b.DefaultReps <= 0 {
		return fmt.Errorf("default_reps must be > 0")
	}
	if !b.AllTasks && len(b.Tasks) == 0 {
		return fmt.Errorf("tasks: list is empty (use \"all\" to defer to harness)")
	}
	return nil
}

// concurrencyGroup mirrors one entry under groups: in
// scripts/benchmark/concurrency-groups.yaml.
type concurrencyGroup struct {
	ID             string `json:"id"`
	MaxConcurrency int    `json:"max_concurrency"`
	Description    string `json:"description,omitempty"`
}

type concurrencyGroupsFile struct {
	Groups map[string]struct {
		MaxConcurrency int    `yaml:"max_concurrency"`
		Description    string `yaml:"description"`
	} `yaml:"groups"`
}

func loadConcurrencyGroups(path string) (map[string]concurrencyGroup, error) {
	raw, err := os.ReadFile(path) // #nosec G304 -- operator-supplied path
	if err != nil {
		return nil, fmt.Errorf("read concurrency-groups %s: %w", path, err)
	}
	var f concurrencyGroupsFile
	dec := yaml.NewDecoder(strings.NewReader(string(raw)))
	dec.KnownFields(true)
	if err := dec.Decode(&f); err != nil {
		return nil, fmt.Errorf("parse concurrency-groups %s: %w", path, err)
	}
	out := make(map[string]concurrencyGroup, len(f.Groups))
	for id, g := range f.Groups {
		out[id] = concurrencyGroup{
			ID:             id,
			MaxConcurrency: g.MaxConcurrency,
			Description:    strings.TrimSpace(g.Description),
		}
	}
	return out, nil
}

// planCell is a single (profile, framework, dataset, task, rep) cell awaiting
// execution. The shell driver iterates these one-to-one.
type planCell struct {
	ProfileID        string `json:"profile_id"`
	Framework        string `json:"framework"`
	Dataset          string `json:"dataset"`
	Task             string `json:"task"`
	Rep              int    `json:"rep"`
	ConcurrencyGroup string `json:"concurrency_group,omitempty"`
}

// planOutput is the top-level JSON document the shell driver consumes.
type planOutput struct {
	BenchSet           *benchSet                   `json:"bench_set"`
	Profiles           []*profile.Profile          `json:"profiles"`
	ConcurrencyGroups  map[string]concurrencyGroup `json:"concurrency_groups"`
	Cells              []planCell                  `json:"cells"`
	UnknownConcurrency []string                    `json:"unknown_concurrency_groups,omitempty"`
}

// resolveProfiles loads each id in the comma-separated list, returning them
// in input order. Profiles are loaded by filename (id.yaml) under profilesDir.
func resolveProfiles(profilesDir string, ids []string) ([]*profile.Profile, error) {
	out := make([]*profile.Profile, 0, len(ids))
	seen := make(map[string]bool, len(ids))
	for _, id := range ids {
		id = strings.TrimSpace(id)
		if id == "" {
			continue
		}
		if seen[id] {
			return nil, fmt.Errorf("profile %q listed twice", id)
		}
		seen[id] = true
		path := filepath.Join(profilesDir, id+".yaml")
		p, err := profile.Load(path)
		if err != nil {
			return nil, err
		}
		if p.ID != id {
			return nil, fmt.Errorf("profile %s: id field %q does not match filename", path, p.ID)
		}
		out = append(out, p)
	}
	if len(out) == 0 {
		return nil, fmt.Errorf("no profiles resolved")
	}
	return out, nil
}

// buildPlan expands the profile × bench-set cross-product into a deterministic
// list of cells. Iteration order: profile (input order), task (bench-set
// order), rep (1..reps).
func buildPlan(profiles []*profile.Profile, bs *benchSet, reps int, groups map[string]concurrencyGroup) (*planOutput, error) {
	if reps <= 0 {
		reps = bs.DefaultReps
	}
	if bs.AllTasks {
		return nil, fmt.Errorf("bench-set %s: tasks: all requires harness-side enumeration not yet supported by plan helper", bs.ID)
	}
	cells := make([]planCell, 0, len(profiles)*len(bs.Tasks)*reps)
	unknown := make(map[string]bool)
	for _, p := range profiles {
		cg := p.ConcurrencyGroup
		if cg != "" {
			if _, ok := groups[cg]; !ok {
				unknown[cg] = true
			}
		}
		for _, task := range bs.Tasks {
			for r := 1; r <= reps; r++ {
				cells = append(cells, planCell{
					ProfileID:        p.ID,
					Framework:        bs.Framework,
					Dataset:          bs.Dataset,
					Task:             task,
					Rep:              r,
					ConcurrencyGroup: cg,
				})
			}
		}
	}
	out := &planOutput{
		BenchSet:          bs,
		Profiles:          profiles,

package main

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
)

// cmdBenchSets implements `fiz-bench bench-sets` (alias used by the shell
// driver). Subcommand-less invocation lists known bench-sets.
func cmdBenchSets(args []string) int {
	if len(args) > 0 {
		switch args[0] {
		case "list":
			return cmdBenchSetsList(args[1:])
		case "help", "-h", "--help":
			fmt.Fprintf(os.Stderr, "Usage: %s bench-sets [list] [--dir <path>] [--json]\n", benchCommandName())
			return 0
		}
	}
	return cmdBenchSetsList(args)
}

func cmdBenchSetsList(args []string) int {
	fs := flagSet("bench-sets list")
	dir := fs.String("dir", "", "Bench-sets directory (default: scripts/benchmark/bench-sets relative to --work-dir)")
	workDir := fs.String("work-dir", "", "Repository root (default: cwd)")
	jsonOut := fs.Bool("json", false, "Emit JSON array instead of table")
	if err := fs.Parse(args); err != nil {
		return 2
	}
	bdir := *dir
	if bdir == "" {
		bdir = filepath.Join(resolveWorkDir(*workDir), defaultBenchSetsDir)
	}
	entries, err := os.ReadDir(bdir)
	if err != nil {
		fmt.Fprintf(os.Stderr, "%s bench-sets: %v\n", benchCommandName(), err)
		return 1
	}
	sets := make([]*benchSet, 0, len(entries))
	for _, e := range entries {
		if e.IsDir() {
			continue
		}
		ext := strings.ToLower(filepath.Ext(e.Name()))
		if ext != ".yaml" && ext != ".yml" {
			continue
		}
		bs, err := loadBenchSet(filepath.Join(bdir, e.Name()))
		if err != nil {
			fmt.Fprintf(os.Stderr, "%s bench-sets: %v\n", benchCommandName(), err)
			return 1
		}
		sets = append(sets, bs)
	}
	sort.Slice(sets, func(i, j int) bool { return sets[i].ID < sets[j].ID })

	if *jsonOut {
		data, _ := json.MarshalIndent(sets, "", "  ")
		fmt.Println(string(data))
		return 0
	}
	if len(sets) == 0 {
		fmt.Printf("No bench-sets found in %s.\n", bdir)
		return 0
	}
	fmt.Printf("%-32s %-16s %-22s %-8s %-6s\n", "ID", "FRAMEWORK", "DATASET", "REPS", "TASKS")
	fmt.Printf("%-32s %-16s %-22s %-8s %-6s\n", "--", "---------", "-------", "----", "-----")
	for _, bs := range sets {
		tasks := fmt.Sprintf("%d", len(bs.Tasks))
		if bs.AllTasks {
			tasks = "all"
		}
		fmt.Printf("%-32s %-16s %-22s %-8d %-6s\n", bs.ID, bs.Framework, bs.Dataset, bs.DefaultReps, tasks)
	}
	return 0
}

package main

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"

	"github.com/easel/fizeau/internal/benchmark/profile"
)

const defaultProfilesDir = "scripts/benchmark/profiles"

func cmdProfiles(args []string) int {
	if len(args) == 0 {
		fmt.Fprintf(os.Stderr, "Usage: %s profiles <subcommand>\n\nSubcommands:\n  list   List profiles under scripts/benchmark/profiles/\n", benchCommandName())
		return 2
	}
	switch args[0] {
	case "list":
		return cmdProfilesList(args[1:])
	case "help", "-h", "--help":
		fmt.Fprintf(os.Stderr, "Usage: %s profiles list [--dir <path>] [--json]\n", benchCommandName())
		return 0
	default:
		fmt.Fprintf(os.Stderr, "%s profiles: unknown subcommand %q\n", benchCommandName(), args[0])
		return 2
	}
}

func cmdProfilesList(args []string) int {
	fs := flagSet("profiles list")
	dir := fs.String("dir", "", "Profiles directory (default: scripts/benchmark/profiles relative to --work-dir)")
	workDir := fs.String("work-dir", "", "Repository root (default: cwd)")
	jsonOut := fs.Bool("json", false, "Emit JSON array instead of table")
	if err := fs.Parse(args); err != nil {
		return 2
	}

	profilesDir := *dir
	if profilesDir == "" {
		profilesDir = filepath.Join(resolveWorkDir(*workDir), defaultProfilesDir)
	}

	profiles, err := profile.LoadDir(profilesDir)
	if err != nil {
		fmt.Fprintf(os.Stderr, "%s profiles list: %v\n", benchCommandName(), err)
		return 1
	}

	if *jsonOut {
		data, _ := json.MarshalIndent(profiles, "", "  ")
		fmt.Println(string(data))
		return 0
	}

	if len(profiles) == 0 {
		fmt.Printf("No profiles found in %s.\n", profilesDir)
		return 0
	}

	fmt.Printf("%-24s %-14s %-32s %-12s %-12s\n", "ID", "PROVIDER", "MODEL", "IN $/Mtok", "OUT $/Mtok")
	fmt.Printf("%-24s %-14s %-32s %-12s %-12s\n", "--", "--------", "-----", "---------", "----------")
	for _, p := range profiles {
		fmt.Printf("%-24s %-14s %-32s %-12.4f %-12.4f\n",
			p.ID,
			string(p.Provider.Type),
			p.Provider.Model,
			p.Pricing.InputUSDPerMTok,
			p.Pricing.OutputUSDPerMTok,
		)
	}
	return 0
}

