		if err == nil && info.Name() == "report.json" && targetReport == "" {
			targetReport = path
		}
		return nil
	})

	if targetReport == "" {
		t.Fatalf("no report.json found to mark invalid")
	}

	// Read and modify the report to have invalid_class set
	reportData, err := os.ReadFile(targetReport)
	if err != nil {
