func getRepoRoot(t *testing.T) string {
	wd, err := os.Getwd()
	if err != nil {
		t.Fatalf("failed to get working directory: %v", err)
	}
	return filepath.Dir(wd)
}

func benchmarkScriptPath(t *testing.T) (string, string) {
	t.Helper()
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")
	if _, err := os.Stat(benchmarkScript); err != nil {
		t.Fatalf("benchmark script not found: %v", err)
	}
	return benchmarkScript, benchDir
}

func runBenchmarkScript(t *testing.T, env map[string]string, args ...string) (string, string, error) {
	t.Helper()
	benchmarkScript, benchDir := benchmarkScriptPath(t)

	cmd := exec.Command(benchmarkScript, args...)
	cmd.Dir = benchDir
	cmd.Env = os.Environ()
	if len(env) > 0 {
		keys := make([]string, 0, len(env))
		for k := range env {
			keys = append(keys, k)
		}
		sort.Strings(keys)
		for _, k := range keys {
			cmd.Env = append(cmd.Env, fmt.Sprintf("%s=%s", k, env[k]))
		}
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr
	err := cmd.Run()
	return stdout.String(), stderr.String(), err
}

func computeHarborSourceSHA(t *testing.T) string {
	t.Helper()

	repoRoot := getRepoRoot(t)
	benchmarkDir := filepath.Join(repoRoot, "scripts", "benchmark")
	adaptersDir := filepath.Join(benchmarkDir, "harbor_adapters")
	agentFile := filepath.Join(benchmarkDir, "harbor_agent.py")
	dockerfile := filepath.Join(benchmarkDir, "Dockerfile.harbor-runner")

	var files []string
	if err := filepath.WalkDir(adaptersDir, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if d.IsDir() {
			return nil
		}
		files = append(files, path)
		return nil
	}); err != nil {
		t.Fatalf("walk harbor adapters: %v", err)
	}
	files = append(files, agentFile, dockerfile)
	sort.Strings(files)

	h := sha256.New()
	for _, path := range files {
		raw, err := os.ReadFile(path)
		if err != nil {
			t.Fatalf("read %s: %v", path, err)
		}
		sum := sha256.Sum256(raw)
		rel := path
		if strings.HasPrefix(rel, benchmarkDir+string(filepath.Separator)) {
			rel = strings.TrimPrefix(rel, benchmarkDir+string(filepath.Separator))
		}
		if _, err := fmt.Fprintf(h, "%s  %s\n", hex.EncodeToString(sum[:]), rel); err != nil {
			t.Fatalf("format source sha entry: %v", err)
		}
	}
	return hex.EncodeToString(h.Sum(nil))
}

// TestBenchmarkRunnerPlanExpansion verifies --plan output for profile×task×rep expansion
// including tasks_from resolution.
func TestBenchmarkRunnerPlanExpansion(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	if _, err := os.Stat(benchmarkScript); err != nil {
		t.Fatalf("benchmark script not found: %v", err)
	}

	tests := []struct {
		name        string
		profile     string
		benchSet    string
		expectRows  int
		shouldError bool
	}{
		{
			name:       "simple canary plan",
			profile:    "claude-sonnet-4-6",
			benchSet:   "tb-2-1-canary",
			expectRows: 9, // 1 profile × 3 tasks × 3 reps
		},
		{
			name:        "missing profile",
			profile:     "nonexistent-profile",
			benchSet:    "tb-2-1-canary",
			shouldError: true,
		},
		{
			name:        "missing bench-set",
			profile:     "claude-sonnet-4-6",
			benchSet:    "nonexistent-bench-set",
			shouldError: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			cmd := exec.Command(benchmarkScript,
				"--profile", tt.profile,
				"--bench-set", tt.benchSet,
				"--plan")
			cmd.Dir = benchDir

			var stdout, stderr bytes.Buffer
			cmd.Stdout = &stdout
			cmd.Stderr = &stderr

			err := cmd.Run()
			if tt.shouldError {
				if err == nil {
					t.Errorf("expected error but command succeeded")
				}
				return
			}

			if err != nil {
				t.Fatalf("command failed: %v\nstderr: %s", err, stderr.String())
			}

			// Parse output: each line is tab-separated key=value pairs
			lines := strings.Split(strings.TrimSpace(stdout.String()), "\n")
			if len(lines) == 0 || (len(lines) == 1 && lines[0] == "") {
				t.Fatalf("no output from --plan")
			}

			if len(lines) != tt.expectRows {
				t.Errorf("expected %d rows, got %d\noutput: %s",
					tt.expectRows, len(lines), stdout.String())
			}

			// Validate each line has expected fields
			for i, line := range lines {
				fields := strings.Split(line, "\t")
				expectedFields := map[string]bool{
					"profile":       false,
					"bench_set":     false,
					"framework":     false,
					"dataset":       false,
					"task":          false,
					"rep":           false,
					"task_executor": false,
				}

				for _, field := range fields {
					parts := strings.SplitN(field, "=", 2)
					if len(parts) == 2 {
						expectedFields[parts[0]] = true
					}
				}

				for key, found := range expectedFields {
					if !found {
						t.Errorf("row %d missing field '%s': %s", i, key, line)
					}
				}
			}
		})
	}
}

