// TestBenchmarkDispatchSubcommands verifies subcommand dispatch, no-subcommand
// run-mode dispatch, and documented usage failures for invalid arguments.
func TestBenchmarkDispatchSubcommands(t *testing.T) {
	t.Run("supported subcommands", func(t *testing.T) {
		repoRoot := getRepoRoot(t)
		outDir := filepath.Join(t.TempDir(), "out")
		tasksDir := filepath.Join(t.TempDir(), "tasks")
		if err := os.MkdirAll(tasksDir, 0o755); err != nil {
			t.Fatalf("mkdir tasks dir: %v", err)
		}

		fakeDockerDir := t.TempDir()
		dockerStub := filepath.Join(fakeDockerDir, "docker")
		sourceSHA := computeHarborSourceSHA(t)
		dockerStubBody := fmt.Sprintf(`#!/usr/bin/env bash
set -euo pipefail
case "${1:-}" in
  image)
    if [[ "${2:-}" == "inspect" ]]; then
      printf '%%s\n' %q
      exit 0
    fi
    ;;
esac
exit 0
`, sourceSHA)
		if err := os.WriteFile(dockerStub, []byte(dockerStubBody), 0o755); err != nil {
			t.Fatalf("write docker stub: %v", err)
		}

		cases := []struct {
			name string
			args []string
			env  map[string]string
			want string
		}{
			{name: "profiles", args: []string{"profiles"}, want: "noop"},
			{name: "bench-sets", args: []string{"bench-sets"}, want: "tb-2-1-canary"},
			{name: "task-executors", args: []string{"task-executors"}, want: "harbor"},
			{name: "harness-adapters", args: []string{"harness-adapters"}, want: "fiz"},
			{name: "validate", args: []string{"validate"}},
			{name: "preflight", args: []string{"preflight"}, env: map[string]string{"PATH": fakeDockerDir + string(os.PathListSeparator) + os.Getenv("PATH")}, want: "preflight: source image-content-sha="},
			{
				name: "run-mode",
				args: []string{"--profile", "noop", "--bench-set", "tb-2-1-canary", "--reps", "1", "--out", outDir},
				env: map[string]string{
					"BENCH_TASKS_DIR":                tasksDir,
					"HARBOR_TASK_EXECUTOR_DRY_RUN":   "1",
					"BENCH_HARBOR_DIGEST_OVERRIDE":   "sha256:test-digest",
					"FIZEAU_BENCH_STATE_DIR":         filepath.Join(t.TempDir(), "state"),
					"BENCH_TERM_GRACE_SECONDS":       "1",
					"BENCH_RETRY_MAX_ATTEMPTS":       "1",
					"BENCH_RETRY_BACKOFF_BASE":       "0",
					"BENCH_TASK_EXECUTOR_OVERRIDE":   filepath.Join(repoRoot, "scripts", "benchmark", "task-executors", "harbor"),
					"BENCHMARK_RUNNER_TEST_DISABLE":  "0",
				},
			},
		}

		for _, tt := range cases {
			t.Run(tt.name, func(t *testing.T) {
				env := map[string]string{
					"BENCH_HARBOR_DIGEST_OVERRIDE": "sha256:test-digest",
				}
				for k, v := range tt.env {
					env[k] = v
				}
				stdout, stderr, err := runBenchmarkScript(t, env, tt.args...)
				if err != nil {
					t.Fatalf("command failed: %v\nstderr: %s", err, stderr)
				}
				if tt.want != "" && !strings.Contains(stdout+stderr, tt.want) {
					t.Fatalf("output does not contain %q\nstdout: %s\nstderr: %s", tt.want, stdout, stderr)
				}
				if tt.name == "run-mode" {
					sweepPath := filepath.Join(outDir, "sweep.json")
					if _, err := os.Stat(sweepPath); err != nil {
						t.Fatalf("run-mode did not create sweep.json: %v", err)
					}
					matches, err := filepath.Glob(filepath.Join(outDir, "cells", "*", "*", "*", "report.json"))
					if err != nil {
						t.Fatalf("glob reports: %v", err)
					}
					if len(matches) == 0 {
						t.Fatal("run-mode did not create any report.json files")
					}
				}
			})
		}

		}
	})

	t.Run("invalid args", func(t *testing.T) {
		cases := []struct {
			name   string
			args   []string
			want   string
			exit   int
		}{
			{name: "unknown subcommand", args: []string{"unknown-subcommand"}, want: "unknown subcommand", exit: 2},
			{name: "missing --profile", args: []string{"--bench-set", "tb-2-1-canary", "--plan"}, want: "--profile", exit: 2},
			{name: "missing --bench-set", args: []string{"--profile", "noop", "--plan"}, want: "--bench-set", exit: 2},
			{name: "unknown flag", args: []string{"--unknown-flag", "value"}, want: "unknown flag", exit: 2},
		}

		for _, tt := range cases {
			t.Run(tt.name, func(t *testing.T) {
				stdout, stderr, err := runBenchmarkScript(t, nil, tt.args...)
				if err == nil {
