 27	func benchmarkScriptPath(t *testing.T) (string, string) {
 28		t.Helper()
 29		repoRoot := getRepoRoot(t)
 30		benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
 31		benchDir := filepath.Join(repoRoot, "scripts", "benchmark")
