 38	func runBenchmarkScript(t *testing.T, env map[string]string, args ...string) (string, string, error) {
 39		t.Helper()
 40		benchmarkScript, benchDir := benchmarkScriptPath(t)
 41	
 42		cmd := exec.Command(benchmarkScript, args...)
 43		cmd.Dir = benchDir
 44		envMap := map[string]string{}
 45		for _, kv := range os.Environ() {
 46			key, value, ok := strings.Cut(kv, "=")
 47			if !ok {
 48				continue
 49			}
 50			envMap[key] = value
 51		}
 52		for k, v := range env {
 53			envMap[k] = v
 54		}
 55		keys := make([]string, 0, len(envMap))
 56		for k := range envMap {
 57			keys = append(keys, k)
 58		}
 59		sort.Strings(keys)
 60		cmd.Env = make([]string, 0, len(envMap))
 61		for _, k := range keys {
 62			cmd.Env = append(cmd.Env, fmt.Sprintf("%s=%s", k, envMap[k]))
 63		}
 64	
 65		var stdout, stderr bytes.Buffer
 66		cmd.Stdout = &stdout
 67		cmd.Stderr = &stderr
 68		err := cmd.Run()
 69		return stdout.String(), stderr.String(), err
 70	}
