 72	func computeHarborSourceSHA(t *testing.T) string {
 73		t.Helper()
 74	
 75		repoRoot := getRepoRoot(t)
 76		benchmarkDir := filepath.Join(repoRoot, "scripts", "benchmark")
 77		adaptersDir := filepath.Join(benchmarkDir, "harbor_adapters")
 78		agentFile := filepath.Join(benchmarkDir, "harbor_agent.py")
 79		dockerfile := filepath.Join(benchmarkDir, "Dockerfile.harbor-runner")
 80	
 81		var files []string
 82		if err := filepath.WalkDir(adaptersDir, func(path string, d fs.DirEntry, err error) error {
 83			if err != nil {
 84				return err
 85			}
 86			if d.IsDir() {
 87				return nil
 88			}
 89			files = append(files, path)
 90			return nil
 91		}); err != nil {
 92			t.Fatalf("walk harbor adapters: %v", err)
 93		}
 94		sort.Strings(files)
 95		files = append(files, agentFile, dockerfile)
 96	
 97		h := sha256.New()
 98		for _, path := range files {
 99			raw, err := os.ReadFile(path)
100			if err != nil {
101				t.Fatalf("read %s: %v", path, err)
102			}
103			sum := sha256.Sum256(raw)
104			rel := path
105			if strings.HasPrefix(rel, benchmarkDir+string(filepath.Separator)) {
106				rel = strings.TrimPrefix(rel, benchmarkDir+string(filepath.Separator))
107			}
108			if _, err := fmt.Fprintf(h, "%s  %s\n", hex.EncodeToString(sum[:]), rel); err != nil {
109				t.Fatalf("format source sha entry: %v", err)
110			}
111		}
112		return hex.EncodeToString(h.Sum(nil))
113	}
